<script lang="ts">
  import FlamePanel from '../lib/algorithms/thinking-traces/FlamePanel.svelte';
  import { VARIANCE_TRACES } from '../lib/data/variance-traces';
  import taskSrc from '../lib/data/sonnet-variance/algo_evl.tsk?raw';
  import referenceSrc from '../lib/data/sonnet-variance/reference.lam?raw';
  import sonnet1 from '../lib/data/sonnet-variance/sonnet-1.lam?raw';
  import sonnet2 from '../lib/data/sonnet-variance/sonnet-2.lam?raw';
  import sonnet3 from '../lib/data/sonnet-variance/sonnet-3.lam?raw';
  import sonnet4 from '../lib/data/sonnet-variance/sonnet-4.lam?raw';
  import sonnet5 from '../lib/data/sonnet-variance/sonnet-5.lam?raw';

  const taskDescription = taskSrc.split('\n---\n')[0].trim();

  const TASK_URL =
    'https://github.com/VictorTaelin/lambench/blob/main/tsk/algo_evl.tsk';
  const REFERENCE_URL =
    'https://github.com/VictorTaelin/lambench/blob/main/lam/algo_evl.lam';

  const solutions: string[] = [sonnet1, sonnet2, sonnet3, sonnet4, sonnet5];

  // For each chart: array-positions of rows in temporal order (start asc, depth asc).
  // Highlighting traverses every span AND every leaf in the order they happen.
  const playSequences: number[][] = VARIANCE_TRACES.map((trace) =>
    trace.rows
      .map((r, idx) => ({ start: r.start, depth: r.depth, idx }))
      .sort((a, b) => a.start - b.start || a.depth - b.depth)
      .map((x) => x.idx),
  );

  // One play state per chart: which step in the playSequence (or null).
  const playState: (number | null)[] = $state(VARIANCE_TRACES.map(() => null));
  const timers: (ReturnType<typeof setInterval> | null)[] =
    VARIANCE_TRACES.map(() => null);

  const STEP_MS = 200;

  function play(i: number) {
    if (timers[i]) {
      clearInterval(timers[i]!);
      timers[i] = null;
      playState[i] = null;
      return;
    }
    const total = playSequences[i]!.length;
    playState[i] = 0;
    timers[i] = setInterval(() => {
      const cur = playState[i];
      if (cur === null || cur === undefined) return;
      const next = cur + 1;
      if (next >= total) {
        clearInterval(timers[i]!);
        timers[i] = null;
        setTimeout(() => { playState[i] = null; }, 800);
        return;
      }
      playState[i] = next;
    }, STEP_MS);
  }

  function currentArrayIdx(chartIdx: number): number | null {
    const ps = playState[chartIdx];
    if (ps === null || ps === undefined) return null;
    return playSequences[chartIdx]?.[ps] ?? null;
  }
</script>

